#!/usr/bin/env python3
"""
Deployment automation script for CI/CD pipeline.
Installs dependencies, runs tests, and packages for deployment.
"""

import subprocess
import sys
import os
import shutil
import tarfile
import json
from datetime import datetime, timezone
from pathlib import Path


# Configuration
PROJECT_ROOT = Path(__file__).parent.resolve()
REQUIREMENTS_FILE = PROJECT_ROOT / "requirements.txt"
TEST_DIR = PROJECT_ROOT / "tests"
SRC_DIR = PROJECT_ROOT / "src"
DIST_DIR = PROJECT_ROOT / "dist"
BUILD_DIR = PROJECT_ROOT / "build"
PACKAGE_NAME = "app-deployment"
VENV_DIR = PROJECT_ROOT / ".venv"

# Files/dirs to include in the deployment package
PACKAGE_INCLUDES = [
    "src",
    "requirements.txt",
    "config",
    "migrations",
    "static",
    "templates",
    "README.md",
]

# Files/dirs to exclude from the deployment package
PACKAGE_EXCLUDES = [
    "__pycache__",
    "*.pyc",
    ".git",
    ".env",
    ".venv",
    "tests",
    "dist",
    "build",
    ".pytest_cache",
    ".mypy_cache",
    "*.egg-info",
    ".tox",
    "node_modules",
]


class DeploymentError(Exception):
    """Custom exception for deployment failures."""
    pass


class Colors:
    """ANSI color codes for terminal output."""
    GREEN = "\033[92m"
    RED = "\033[91m"
    YELLOW = "\033[93m"
    BLUE = "\033[94m"
    BOLD = "\033[1m"
    RESET = "\033[0m"


def log_step(message):
    print(f"\n{Colors.BLUE}{Colors.BOLD}{'='*60}")
    print(f"  {message}")
    print(f"{'='*60}{Colors.RESET}\n")


def log_success(message):
    print(f"{Colors.GREEN}✓ {message}{Colors.RESET}")


def log_warning(message):
    print(f"{Colors.YELLOW}⚠ {message}{Colors.RESET}")


def log_error(message):
    print(f"{Colors.RED}✗ {message}{Colors.RESET}")


def run_command(command, description=None, cwd=None, env=None):
    """Run a shell command and handle errors."""
    if description:
        print(f"  → {description}")

    merged_env = os.environ.copy()
    if env:
        merged_env.update(env)

    try:
        result = subprocess.run(
            command,
            cwd=cwd or PROJECT_ROOT,
            env=merged_env,
            capture_output=True,
            text=True,
            timeout=300,
        )

        if result.stdout.strip():
            for line in result.stdout.strip().split("\n"):
                print(f"    {line}")

        if result.returncode != 0:
            if result.stderr.strip():
                for line in result.stderr.strip().split("\n"):
                    log_error(f"    {line}")
            raise DeploymentError(
                f"Command failed with exit code {result.returncode}: {' '.join(command)}"
            )

        return result

    except subprocess.TimeoutExpired:
        raise DeploymentError(f"Command timed out: {' '.join(command)}")
    except FileNotFoundError:
        raise DeploymentError(f"Command not found: {command[0]}")


def check_prerequisites():
    """Check that all required tools and files are available."""
    log_step("Checking prerequisites")

    # Check Python version
    python_version = sys.version_info
    if python_version < (3, 8):
        raise DeploymentError(
            f"Python 3.8+ required, found {python_version.major}.{python_version.minor}"
        )
    log_success(f"Python version: {python_version.major}.{python_version.minor}.{python_version.micro}")

    # Check pip is available
    run_command([sys.executable, "-m", "pip", "--version"], "Checking pip")
    log_success("pip is available")

    # Check requirements.txt exists
    if not REQUIREMENTS_FILE.exists():
        raise DeploymentError(f"Requirements file not found: {REQUIREMENTS_FILE}")
    log_success(f"Requirements file found: {REQUIREMENTS_FILE}")

    # Check source directory exists
    if not SRC_DIR.exists():
        log_warning(f"Source directory not found: {SRC_DIR} (will package root instead)")

    # Check test directory exists
    if not TEST_DIR.exists():
        log_warning(f"Test directory not found: {TEST_DIR}")

    log_success("All prerequisites met")


def install_dependencies():
    """Install project dependencies from requirements.txt."""
    log_step("Installing dependencies")

    # Upgrade pip first
    run_command(
        [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
        "Upgrading pip",
    )

    # Install dependencies
    run_command(
        [
            sys.executable, "-m", "pip", "install",
            "-r", str(REQUIREMENTS_FILE),
            "--no-cache-dir",
            "--quiet",
        ],
        f"Installing from {REQUIREMENTS_FILE.name}",
    )

    # Install test dependencies if they exist
    test_requirements = PROJECT_ROOT / "requirements-test.txt"
    if test_requirements.exists():
        run_command(
            [
                sys.executable, "-m", "pip", "install",
                "-r", str(test_requirements),
                "--no-cache-dir",
                "--quiet",
            ],
            f"Installing test dependencies from {test_requirements.name}",
        )
    else:
        # Ensure pytest is available for testing
        run_command(
            [
                sys.executable, "-m", "pip", "install",
                "pytest", "pytest-cov",
                "--no-cache-dir",
                "--quiet",
            ],
            "Installing pytest and pytest-cov",
        )

    # Verify installation by listing installed packages
    result = run_command(
        [sys.executable, "-m", "pip", "list", "--format=columns"],
        "Verifying installed packages",
    )

    log_success("Dependencies installed successfully")


def run_linting():
    """Run code linting checks if linting tools are available."""
    log_step("Running code quality checks")

    linters_run = 0

    # Try running flake8
    try:
        run_command(
            [sys.executable, "-m", "flake8", str(SRC_DIR), "--max-line-length=120", "--statistics"],
            "Running flake8 lint check",
        )
        log_success("flake8 passed")
        linters_run += 1
    except DeploymentError:
        log_warning("flake8 check failed or not available, continuing...")

    # Try running basic Python syntax check
    try:
        py_files = list(SRC_DIR.rglob("*.py")) if SRC_DIR.exists() else list(PROJECT_ROOT.rglob("*.py"))
        # Filter out venv, build, dist directories
        py_files = [
            f for f in py_files
            if not any(part in f.parts for part in [".venv", "venv", "build", "dist", "node_modules"])
        ]

        for py_file in py_files:
            run_command(
                [sys.executable, "-m", "py_compile", str(py_file)],
            )
        log_success(f"Syntax check passed for {len(py_files)} Python files")
        linters_run += 1
    except DeploymentError as e:
        raise DeploymentError(f"Python syntax check failed: {e}")

    if linters_run == 0:
        log_warning("No linting tools were run")
    else:
        log_success(f"Code quality checks passed ({linters_run} checks)")


def run_tests():
    """Run the application test suite."""
    log_step("Running tests")

    if not TEST_DIR.exists():
        log_warning("No test directory found, skipping tests")
        return

    test_files = list(TEST_DIR.rglob("test_*.py")) + list(TEST_DIR.rglob("*_test.py"))
    if not test_files:
        log_warning("No test files found, skipping tests")
        return

    print(f"  Found {len(test_files)} test file(s)")

    # Create reports directory
    reports_dir = PROJECT_ROOT / "reports"
    reports_dir.mkdir(exist_ok=True)

    # Run pytest with coverage
    pytest_args = [
        sys.executable, "-m", "pytest",
        str(TEST_DIR),
        "-v",
        "--tb=short",
        f"--junitxml={reports_dir / 'test-results.xml'}",
    ]

    # Add coverage if source directory exists
    if SRC_DIR.exists():
        pytest_args.extend([
            f"--cov={SRC_DIR}",
            "--cov-report=term-missing",
            f"--cov-report=html:{reports_dir / 'coverage-html'}",
            f"--cov-report=xml:{reports_dir / 'coverage.xml'}",
        ])

    # Check for a pytest configuration
    pytest_ini = PROJECT_ROOT / "pytest.ini"
    pyproject_toml = PROJECT_ROOT / "pyproject.toml"
    setup_cfg = PROJECT_ROOT / "setup.cfg"

    if pytest_ini.exists():
        print(f"  Using config from: {pytest_ini}")
    elif pyproject_toml.exists():
        print(f"  Using config from: {pyproject_toml}")
    elif setup_cfg.exists():
        print(f"  Using config from: {setup_cfg}")

    run_command(pytest_args, "Running pytest")

    log_success("All tests passed")


def clean_build_artifacts():
    """Clean previous build and dist directories."""
    log_step("Cleaning build artifacts")

    for directory in [DIST_DIR, BUILD_DIR]:
        if directory.exists():
            shutil.rmtree(directory)
            log_success(f"Removed {directory}")

    # Clean __pycache__ directories
    pycache_count = 0
    for pycache in PROJECT_ROOT.rglob("__pycache__"):
        if ".venv" not in str(pycache) and "venv" not in str(pycache):
            shutil.rmtree(pycache)
            pycache_count += 1

    if pycache_count:
        log_success(f"Removed {pycache_count} __pycache__ directories")

    # Clean .pyc files
    pyc_count = 0
    for pyc_file in PROJECT_ROOT.rglob("*.pyc"):
        if ".venv" not in str(pyc_file) and "venv" not in str(pyc_file):
            pyc_file.unlink()
            pyc_count += 1

    if pyc_count:
        log_success(f"Removed {pyc_count} .pyc files")

    log_success("Build artifacts cleaned")


def generate_build_metadata():
    """Generate build metadata for tracking deployments."""
    metadata = {
        "build_timestamp": datetime.now(timezone.utc).isoformat(),
        "python_version": f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}",
        "platform": sys.platform,
    }

    # Try to get git information
    try:
        git_hash = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True, text=True, cwd=PROJECT_ROOT, timeout=10,
        )
        if git_hash.returncode == 0:
            metadata["git_commit"] = git_hash.stdout.strip()

        git_branch = subprocess.run(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"],
            capture_output=True, text=True, cwd=PROJECT_ROOT, timeout=10,
        )
        if git_branch.returncode == 0:
            metadata["git_branch"] = git_branch.stdout.strip()

        git_tag = subprocess.run(
            ["git", "describe", "--tags", "--always"],
            capture_output=True, text=True, cwd=PROJECT_ROOT, timeout=10,
        )
        if git_tag.returncode == 0:
            metadata["version"] = git_tag.stdout.strip()

        git_dirty = subprocess.run(
            ["git", "status", "--porcelain"],
            capture_output=True, text=True, cwd=PROJECT_ROOT, timeout=10,
        )
        if git_dirty.returncode == 0:
            metadata["git_dirty"] = bool(git_dirty.stdout.strip())

    except (FileNotFoundError, subprocess.TimeoutExpired):
        log_warning("Git not available, skipping git metadata")

    # Get dependency snapshot
    try:
        pip_freeze = subprocess.run(
            [sys.executable, "-m", "pip", "freeze"],
            capture_output=True, text=True, timeout=30,
        )
        if pip_freeze.returncode == 0:
            metadata["dependencies"] = pip_freeze.stdout.strip().split("\n")
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass

    if "version" not in metadata:
        metadata["version"] = datetime.now(timezone.utc).strftime("%Y%m%d.%H%M%S")

    return metadata


def should_include_path(path, root):
    """Check if a path should be included in the deployment package."""
    rel_path = path.relative_to(root)
    parts = rel_path.parts

    for exclude in PACKAGE_EXCLUDES:
        if exclude.startswith("*"):
            # Wildcard suffix match
            suffix = exclude[1:]
            if any(part.endswith(suffix) for part in parts):
                return False
        else:
            if exclude in parts:
                return False

    return True


def package_application():
    """Package the application for deployment."""
    log_step("Packaging application for deployment")

    # Create dist and build directories
    DIST_DIR.mkdir(exist_ok=True)
    BUILD_DIR.mkdir(exist_ok=True)

    # Generate build metadata
    metadata = generate_build_metadata()
    version = metadata.get("version", "unknown")

    # Write metadata to build directory
    metadata_file = BUILD_DIR / "build-metadata.json"
    with open(metadata_file, "w") as f:
        json.dump(metadata, f, indent=2)
    log_success(f"Generated build metadata (version: {version})")

    # Copy files to build directory
    files_copied = 0
    for include_path in PACKAGE_INCLUDES:
        source = PROJECT_ROOT / include_path
        if not source.exists():
            continue

        destination = BUILD_DIR / include_path

        if source.is_file():
            destination.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(source, destination)
            files_copied += 1
        elif source.is_dir():
            # Copy directory with exclusions
            for item in source.rglob("*"):
                if item.is_file() and should_include_path(item, PROJECT_ROOT):
                    rel = item.relative_to(PROJECT_ROOT)
                    dest_file = BUILD_DIR / rel
                    dest_file.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(item, dest_file)
                    files_copied += 1

    # Copy the build metadata into the package
    log_success(f"Copied {files_copied} files to build directory")

    # Create the deployment tarball
    timestamp = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
    safe_version = version.replace("/", "-").replace("\\", "-")
    archive_name = f"{PACKAGE_NAME}-{safe_version}-{timestamp}.tar.gz"
    archive_path = DIST_DIR / archive_name

    with tarfile.open(archive_path, "w:gz") as tar:
        tar.add(BUILD_DIR, arcname=PACKAGE_NAME)

    archive_size = archive_path.stat().st_size
    size_str = format_file_size(archive_size)

    log_success(f"Created deployment package: {archive_path}")
    log_success(f"Package size: {size_str}")

    # Create a latest symlink/copy for convenience
    latest_path = DIST_DIR / f"{PACKAGE_NAME}-latest.tar.gz"
    if latest_path.exists():
        latest_path.unlink()
    try:
        latest_path.symlink_to(archive_path.name)
        log_success(f"Created latest symlink: {latest_path}")
    except OSError:
        # Symlinks may not be supported (e.g., Windows without privileges)
        shutil.copy2(archive_path, latest_path)
        log_success(f"Created latest copy: {latest_path}")

    # Write deployment manifest
    manifest = {
        "package": archive_name,
        "path": str(archive_path),
        "size_bytes": archive_size,
        "size_human": size_str,
        "files_included": files_copied,
        **metadata,
    }
    manifest_path = DIST_DIR / "manifest.json"
    with open(manifest_path, "w") as f:
        json.dump(manifest, f, indent=2)
    log_success(f"Wrote deployment manifest: {manifest_path}")

    return archive_path, manifest


def format_file_size(size_bytes):
    """Format file size in human-readable format."""
    for unit in ["B", "KB", "MB", "GB"]:
        if size_bytes < 1024:
            return f"{size_bytes:.2f} {unit}"
        size_bytes /= 1024
    return f"{size_bytes:.2f} TB"


def print_summary(archive_path, manifest, elapsed_seconds):
    """Print deployment summary."""
    log_step("Deployment Package Summary")

    print(f"  Package:     {archive_path.name}")
    print(f"  Size:        {manifest['size_human']}")
    print(f"  Files:       {manifest['files_included']}")
    print(f"  Version:     {manifest.get('version', 'N/A')}")
    print(f"  Git Commit:  {manifest.get('git_commit', 'N/A')[:12] if manifest.get('git_commit') else 'N/A'}")
    print(f"  Git Branch:  {manifest.get('git_branch', 'N/A')}")
    print(f"  Timestamp:   {manifest.get('build_timestamp', 'N/A')}")
    print(f"  Duration:    {elapsed_seconds:.1f}s")
    print(f"  Output:      {archive_path}")
    print()
    log_success("Deployment package is ready!")


def main():
    """Main deployment pipeline."""
    print(f"\n{Colors.BOLD}{'='*60}")
    print(f"  Deployment Automation Pipeline")
    print(f"  Started: {datetime.now(timezone.utc).isoformat()}")
    print(f"{'='*60}{Colors.RESET}")

    start_time = datetime.now(timezone.utc)

    try:
        # Step 1: Check prerequisites
        check_prerequisites()

        # Step 2: Clean previous build artifacts
        clean_build_artifacts()

        # Step 3: Install dependencies
        install_dependencies()

        # Step 4: Run linting / code quality checks
        run_linting()

        # Step 5: Run tests
        run_tests()

        # Step 6: Package for deployment
        archive_path, manifest = package_application()

        # Summary
        elapsed = (datetime.now(timezone.utc) - start_time).total_seconds()
        print_summary(archive_path, manifest, elapsed)

        return 0

    except DeploymentError as e:
        log_error(f"\nDeployment failed: {e}")
        elapsed = (datetime.now(timezone.utc) - start_time).total_seconds()
        log_error(f"Failed after {elapsed:.1f}s")
        return 1

    except KeyboardInterrupt:
        log_warning("\nDeployment cancelled by user")
        return 130

    except Exception as e:
        log_error(f"\nUnexpected error: {e}")
        import traceback
        traceback.print_exc()
        return 1


if __name__ == "__main__":
    sys.exit(main())